import axios from 'axios';

// 1. Create instance with environment-aware baseURL
const api = axios.create({
  baseURL: process.env.REACT_APP_API_URL || 'http://localhost:8000',
  headers: {
    'Content-Type': 'application/json',
  },
});

/**
 * REQUEST INTERCEPTOR
 * Injects the JWT "Identity" token into every outgoing request node.
 */
api.interceptors.request.use(
  (config) => {
    const token = localStorage.getItem('token');
    if (token) {
      // Ensure the token is attached to the Authorization header
      config.headers.Authorization = `Bearer ${token}`;
    }
    return config;
  },
  (error) => {
    return Promise.reject(error);
  }
);

/**
 * RESPONSE INTERCEPTOR
 * Handles global error states, specifically 401 (Unauthorized).
 * If the terminal session expires, it wipes the token and redirects to login.
 */
api.interceptors.response.use(
  (response) => response, // Pass through successful responses
  (error) => {
    const originalRequest = error.config;

    // Check if error is 401 and not already retrying
    if (error.response?.status === 401 && !originalRequest._retry) {
      console.warn("TERMINAL_SESSION_EXPIRED: Purging identity nodes.");
      
      // Clear the invalid token
      localStorage.removeItem('token');
      
      // Redirect to login page - forces a clean state
      if (window.location.pathname !== '/login') {
        window.location.href = '/login';
      }
    }

    return Promise.reject(error);
  }
);

export default api;
